import Header from './Header';
import Content from './Content';
import Footer from './Footer';
import Additems from './Additems';
import { useState } from 'react';
import ListItems from './ListItems';

function App() {
  const[items,setItems]=useState(JSON)
    const handleChange = (id)=>
    {
      const ListItems =items.map(items => (items.id==id) ?{...items,checked:!items.checked}:items);
      setItems(ListItems);
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const changeDelete=(id)=>
    {
      const ListItems=items.filter(items =>items.id!==id);
      setItems(ListItems);
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const addItem=(activity)=>{
      const id=(items.length)?items[items.length -1].id+1:1
      const addNewItem={id,activity,checked:false}
      const ListItems=[...items,addNewItem]
      setItems(ListItems)
      localStorage.setItem("ToDoList-ListAll",JSON.stringify(ListItems))
    }
    const [newItem,setNewItem]=useState('')
    const handleSumbit=(e)=>{
      e.preventDefault();
      if(!newItem) return;
      addItem(newItem)
      setNewItem('')
    }
  return (
    <div>
    <Header title="To-Do Lists"/>
    <Additems newItem={newItem} setNewItem={setNewItem} handleSumbit={handleSumbit}/>
    <Content items={items} changeDelete={changeDelete} handleChange={handleChange}/>
    <Footer items={items}/>
    </div>
  );
}

export default App;
